// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./Farmer.sol";
import "./Supplier.sol";
import "./Aggregator.sol";
import "./Retailer.sol";
import "./Customer.sol";

contract TrackSupplyChain is Farmer, Supplier, Aggregator, Retailer, Customer {
    address public owner;

    struct FreshnessData {
        uint256 gasValue;
        uint256 temperature;
        uint256 humidity;
        uint256 timestamp;
    }

    // Mapping: productId → freshness info
    mapping(uint256 => FreshnessData) public productFreshness;

    // 🔹 Event to log updates (useful for frontend monitoring)
    event FreshnessUpdated(
        uint256 indexed productId,
        uint256 gasValue,
        uint256 temperature,
        uint256 humidity,
        uint256 timestamp
    );

    constructor() {
        owner = msg.sender;
    }

    // 🔹 Update called by backend (ESP8266 → backend → blockchain)
    function updateFreshness(
        uint256 _productId,
        uint256 _gasValue,
        uint256 _temperature,
        uint256 _humidity
    ) public {
        // ✅ (Optional) Restrict to owner/backend if desired:
        // require(msg.sender == owner, "Only backend (owner) can update freshness");

        productFreshness[_productId] = FreshnessData({
            gasValue: _gasValue,
            temperature: _temperature,
            humidity: _humidity,
            timestamp: block.timestamp
        });

        emit FreshnessUpdated(_productId, _gasValue, _temperature, _humidity, block.timestamp);
    }

    // 🔹 Web3-friendly read function (frontend reads this)
    function getFreshness(uint256 _productId)
        public
        view
        returns (
            uint256 gasValue,
            uint256 temperature,
            uint256 humidity,
            uint256 timestamp
        )
    {
        FreshnessData storage f = productFreshness[_productId];
        return (f.gasValue, f.temperature, f.humidity, f.timestamp);
    }
}

